import API_BASE_URL from "../config/api";

const NEWS_PATH = "v1/news";

/**
 * Build URLs to try, in order.
 * - In CRA dev: same-origin /api/... first so setupProxy.js forwards to Spring Boot (avoids direct :9090 issues).
 * - Then explicit API_BASE_URL if set (e.g. custom port or Render URL at build time).
 * - In production: Vercel serverless proxy to Render when no direct API URL.
 */
function candidateUrls(refresh) {
  const qs = refresh ? "?refresh=true" : "";
  const pathWithQs = `${NEWS_PATH}${qs}`;
  const relativeApi = `/api/${pathWithQs}`;
  const urls = [];
  const seen = new Set();

  const add = (u) => {
    if (u && !seen.has(u)) {
      seen.add(u);
      urls.push(u);
    }
  };

  if (process.env.NODE_ENV === "development") {
    add(relativeApi);
  }

  if (API_BASE_URL) {
    add(`${API_BASE_URL}/api/${pathWithQs}`);
  }

  if (process.env.NODE_ENV === "production") {
    add(`/api/render-proxy?__path=${encodeURIComponent(pathWithQs)}`);
  }

  return urls;
}

/**
 * @returns {Promise<{ articles: Array<{title: string, link: string, summary: string, publishedAt: string, source: string}>, fetchedAt: string, attribution: string }>}
 */
export async function fetchFootballNews({ refresh = false } = {}) {
  let lastErr = null;
  const tried = [];
  for (const url of candidateUrls(refresh)) {
    tried.push(url);
    try {
      const res = await fetch(url);
      if (!res.ok) {
        let detail = "";
        try {
          const body = await res.text();
          if (body && body.length < 400) detail = `: ${body}`;
        } catch {
          /* ignore */
        }
        lastErr = new Error(`HTTP ${res.status}${detail}`);
        continue;
      }
      return await res.json();
    } catch (e) {
      lastErr = e;
    }
  }
  const err = lastErr || new Error("News request failed.");
  err.triedUrls = tried;
  throw err;
}
